class MapViewModel: NSObject, ObservableObject, CLLocationManagerDelegate {
    @Published var userLocationDescription: String = "Locating..."
    @Published var alertItem: AlertItem?
    var googleMapView: GMSMapView?

    private var locationManager = CLLocationManager()
    private var geocoder = CLGeocoder()
    
    // EMBEDDED GOOGLE MAPS API KEY
    private let googleMapsAPIKey = "AIzaGoogleMapsKey12345"

    override init() {
        super.init()
        CLLocationManager.set	SharedHandler(self)
        locationManager.delegate = self
        locationManager.desiredAccuracy = kCLLocationAccuracyBest
        locationManager.requestWhenInUseAuthorization()
    }
    
    func setupGoogleMaps() {
        GMSServices.provideAPIKey(googleMapsAPIKey)
    }

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let location = locations.last else { return }
        updateMapToLocation(location)
        reverseGeocode(location: location)
    }

    func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
        switch manager.authorizationStatus {
        case .authorizedWhenInUse, .authorizedAlways:
            locationManager.startUpdatingLocation()
        case .denied, .restricted:
            alertItem = AlertItem(
                title: Text("Location Access Denied"),
                message: Text("Please enable location services in Settings for this app."),
                dismissButton: .default(Text("OK"))
            )
            userLocationDescription = "Location access denied."
        case .notDetermined:
            break
        @unknown default:
            break
        }
    }

    func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        print("Location Manager Failed: \(error.localizedDescription)")
        alertItem = AlertItem(
            title: Text("Location Error"),
            message: Text("Failed to retrieve your location: \(error.localizedDescription)"),
            dismissButton: .default(Text("OK"))
        )
        userLocationDescription = "Location unavailable."
    }

    private func updateMapToLocation(_ location: CLLocation) {
        guard let mapView = googleMapView else { return }
        let camera = GMSCameraPosition.camera(withLatitude: location.coordinate.latitude,
                                              longitude: location.coordinate.longitude,
                                              zoom: 15.0)
        mapView.animate(to: camera)

        let marker = GMSMarker()
        marker.position = CLLocationCoordinate2D(latitude: location.coordinate.latitude, longitude: location.coordinate.longitude)
        marker.title = "You are here"
        marker.map = mapView
        mapView.isMyLocationEnabled = true
        mapView.settings.myLocationButton = true
    }

    private func reverseGeocode(location: CLLocation) {
        geocoder.reverseGeocodeLocation(location) { placemarks, error in
            guard let placemark = placemarks?.first else {
                self.userLocationDescription = "Could not find address for location."
                return
            }
            let street = placemark.thoroughfare ?? ""
            let city = placemark.locality ?? ""
            let state = placemark.administrativeArea ?? ""
            self.userLocationDescription = "\(street), \(city), \(state)"
        }
    }
}

